// 經典BFS解法class Solution &#123;public:    vector&lt;vector&lt;int&gt;&gt; levelOrder(TreeNode* root) &#123;        vector&lt;vector&lt;int&gt;&gt; ans;        if(root == nullptr) return ans;        queue&lt;TreeNode*&gt; q;        map&lt;TreeNode*, int&gt; mp;        q.push(root);        mp[root] = 0;        while(!q.empty())&#123;            TreeNode* curr = q.front();            q.pop();            int level = mp[curr];            if(ans.size() == level) ans.push_back(&#123;&#125;);            ans.at(level).push_back(curr-&gt;val);            if(curr-&gt;left != nullptr)&#123;                mp[curr-&gt;left] = level+1;                q.push(curr-&gt;left);            &#125;            if(curr-&gt;right != nullptr)&#123;                mp[curr-&gt;right] = level+1;                q.push(curr-&gt;right);            &#125;        &#125;        return ans;    &#125;&#125;;

// 用陣列實作queue的優化BFS解法#define MAXN 2005TreeNode* q[2005];class Solution &#123;public:    vector&lt;vector&lt;int&gt;&gt; levelOrder(TreeNode* root) &#123;        vector&lt;vector&lt;int&gt;&gt; ans;        if(root == nullptr) return ans;        int l = 0, r = 0; // head and tail index, take from head, add to tail        q[r++] = root;        while(l &lt; r)&#123; // !q.empty()            int size = r-l;            vector&lt;int&gt; list;            for(int i=0; i&lt;size; ++i)&#123;                TreeNode* curr = q[l++]; // q.front(), q.pop();                list.push_back(curr-&gt;val);                if(curr-&gt;left != nullptr)&#123;                    q[r++] = curr-&gt;left;                &#125;                if(curr-&gt;right != nullptr)&#123;                    q[r++] = curr-&gt;right;                &#125;            &#125;            ans.push_back(list);        &#125;        return ans;    &#125;&#125;;

題目:https://leetcode.com/problems/jump-game-ii/


提供了兩種寫法，DP與Greedy
#define INF 0x3f3f3f3f#define MAXN 10005class Solution_DP&#123;public:    int dp[MAXN];    // 從0到idx的value = dp[idx];    void solve(vector&lt;int&gt;&amp; nums, int idx)&#123;        if(dp[idx] == INF) return;        int jumps = nums[idx];        for(int i=1; i&lt;=jumps; ++i)&#123;            if(idx + i &lt; nums.size())&#123;                dp[idx+i] = min(dp[idx+i], dp[idx]+1);            &#125;        &#125;    &#125;    int jump(vector&lt;int&gt;&amp; nums) &#123;;        memset(dp, INF, sizeof(dp));        dp[0] = 0;        for(int i=0; i&lt;nums.size(); ++i) solve(nums, i);        return dp[nums.size()-1];    &#125;&#125;;
#define INF 0x3f3f3f3f#define MAXN 10005class Solution_Greedy&#123;public:    int jump(vector&lt;int&gt;&amp; nums)&#123;        if(nums.size() == 1) return 0;        int jumps = 0;        int maxi = 0;        int dist = 0;        for(int i=0; i&lt;nums.size()-1; ++i)&#123; // cur_idx            maxi = max(maxi, i + nums[i]);            if(i == dist)&#123;                dist = maxi;                ++jumps;                if(dist &gt;= nums.size()-1) break; // 已經到終點了            &#125;        &#125;        return jumps;    &#125;&#125;;

