// topologic version#include &lt;bits/stdc++.h&gt;using namespace std;int main()&#123;    int m, n;    while(cin &gt;&gt; m &gt;&gt; n &amp;&amp; m != 0)&#123;        vector&lt;vector&lt;int&gt;&gt; arr(m+5);        vector&lt;int&gt; inDegree(m+5, 0);        int x, y;        while(n--)&#123;            cin &gt;&gt; x &gt;&gt; y;            arr[x].push_back(y); // x precedes y            inDegree[y]++; // indegree of y ++        &#125;        queue&lt;int&gt; q; // free tasks        for(int i=1; i&lt;=m; ++i)&#123;            if(inDegree[i] == 0) q.push(i);        &#125;        vector&lt;int&gt; ans;        while(!q.empty())&#123;            int curr = q.front();            q.pop();            ans.push_back(curr);            for(int successor : arr[curr])&#123; // find successors                inDegree[successor]--;                if(inDegree[successor] == 0) q.push(successor);            &#125;        &#125;        bool flag = true;        for(auto num : ans)&#123;            if(!flag) cout &lt;&lt; &#x27; &#x27;;            flag = false;            cout &lt;&lt; num;        &#125;        cout &lt;&lt; &#x27;\n&#x27;;    &#125;    return 0;&#125;

