#123;        cin &gt;&gt; op &gt;&gt; ws &gt;&gt; word;        switch(op)&#123;            case 1:                insert(word);                break;            case 2:                erase(word);                break;            case 3:                if(search(word)) cout &lt;&lt; &quot;YES
